import { GREEN, RED, DIM, CYAN, BOLD, YELLOW, RESET } from "../utils/colors.js";
const fs = require("fs");
const path = require("path");
function loadConfig() {
  const configPath = path.resolve(process.cwd(), "nodeon.json");
  if (!fs.existsSync(configPath)) {
    return {};
  }
  try {
    return JSON.parse(fs.readFileSync(configPath, "utf8"));
  } catch (e) {
    return {};
  }
}
export async function runDeploy(args) {
  const config = loadConfig();
  const projectDir = process.cwd();
  const target = args[0] ?? config.deploy?.target ?? "docker";
  console.log("");
  console.log("  " + CYAN + BOLD + "🚀 Nodeon deploy" + RESET + " → " + target);
  console.log("");
  if (target === "docker") {
    await deployDocker(projectDir, config, args);
  } else if (target === "vercel") {
    deployVercel(projectDir, config);
  } else if (target === "fly") {
    deployFly(projectDir, config);
  } else {
    console.error("  " + RED + "Unknown deploy target: " + target + RESET);
    console.error("  Supported: docker, vercel, fly");
    process.exit(1);
  }
}
async function deployDocker(projectDir, config, args) {
  const outDir = path.resolve(projectDir, config.outDir ?? "dist");
  const port = config.port ?? 3000;
  const appName = config.name ?? path.basename(projectDir);
  if (!fs.existsSync(outDir) || !fs.existsSync(path.join(outDir, "server.js"))) {
    console.log("  " + YELLOW + "No production build found. Running build first..." + RESET);
    console.log("");
    const buildProd = require("./build-prod.js");
    await buildProd.runBuildProd(["--prod"]);
  }
  const dockerfile = generateDockerfile(port, config);
  const dockerfilePath = path.join(projectDir, "Dockerfile");
  fs.writeFileSync(dockerfilePath, dockerfile, "utf8");
  console.log("  " + GREEN + "✓" + RESET + " Generated Dockerfile");
  const compose = generateDockerCompose(appName, port, config);
  const composePath = path.join(projectDir, "docker-compose.yml");
  fs.writeFileSync(composePath, compose, "utf8");
  console.log("  " + GREEN + "✓" + RESET + " Generated docker-compose.yml");
  const dockerignore = generateDockerignore();
  const ignorePath = path.join(projectDir, ".dockerignore");
  if (!fs.existsSync(ignorePath)) {
    fs.writeFileSync(ignorePath, dockerignore, "utf8");
    console.log("  " + GREEN + "✓" + RESET + " Generated .dockerignore");
  }
  console.log("");
  console.log("  " + DIM + "To build and run:" + RESET);
  console.log("    docker compose up --build");
  console.log("");
  console.log("  " + DIM + "To build image only:" + RESET);
  console.log("    docker build -t " + appName + " .");
  console.log("    docker run -p " + port + ":" + port + " " + appName);
  console.log("");
  if (args.includes("--run")) {
    console.log("  " + CYAN + "Starting container..." + RESET);
    const exec = require("child_process").execSync;
    try {
      exec("docker compose up --build", { stdio: "inherit", cwd: projectDir });
    } catch (e) {

    }
  }
}
function deployVercel(projectDir, config) {
  const outDir = config.outDir ?? "dist";
  const vercelConfig = { version: 2, builds: [{ src: outDir + "/server.js", use: "@vercel/node" }], routes: [{ src: "/_nova/(.*)", dest: "/" + outDir + "/_nova/$1" }, { src: "/(.*)", dest: "/" + outDir + "/server.js" }] };
  const vercelPath = path.join(projectDir, "vercel.json");
  fs.writeFileSync(vercelPath, JSON.stringify(vercelConfig, null, 2), "utf8");
  console.log("  " + GREEN + "✓" + RESET + " Generated vercel.json");
  console.log("");
  console.log("  " + DIM + "Deploy with:" + RESET);
  console.log("    npx vercel --prod");
  console.log("");
}
function deployFly(projectDir, config) {
  const appName = config.name ?? path.basename(projectDir);
  const port = config.port ?? 3000;
  const flyToml = "app = \"" + appName + "\"\n" + "primary_region = \"iad\"\n\n" + "[build]\n" + "  dockerfile = \"Dockerfile\"\n\n" + "[http_service]\n" + "  internal_port = " + port + "\n" + "  force_https = true\n" + "  auto_stop_machines = true\n" + "  auto_start_machines = true\n";
  const flyPath = path.join(projectDir, "fly.toml");
  fs.writeFileSync(flyPath, flyToml, "utf8");
  console.log("  " + GREEN + "✓" + RESET + " Generated fly.toml");
  if (!fs.existsSync(path.join(projectDir, "Dockerfile"))) {
    const dockerfile = generateDockerfile(port, config);
    fs.writeFileSync(path.join(projectDir, "Dockerfile"), dockerfile, "utf8");
    console.log("  " + GREEN + "✓" + RESET + " Generated Dockerfile");
  }
  console.log("");
  console.log("  " + DIM + "Deploy with:" + RESET);
  console.log("    fly launch");
  console.log("    fly deploy");
  console.log("");
}
function generateDockerfile(port, config) {
  const outDir = config.outDir ?? "dist";
  let df = "# Auto-generated by nodeon deploy\n";
  df = df + "FROM node:20-alpine\n\n";
  df = df + "WORKDIR /app\n\n";
  df = df + "# Copy production build\n";
  df = df + "COPY " + outDir + "/ ./dist/\n";
  df = df + "COPY package.json ./\n\n";
  df = df + "# Install production dependencies only\n";
  df = df + "RUN npm ci --omit=dev 2>/dev/null || npm install --omit=dev 2>/dev/null || true\n\n";
  df = df + "ENV NODE_ENV=production\n";
  df = df + "ENV PORT=" + port + "\n\n";
  df = df + "EXPOSE " + port + "\n\n";
  df = df + "CMD [\"node\", \"dist/server.js\"]\n";
  return df;
}
function generateDockerCompose(appName, port, config) {
  let dc = "# Auto-generated by nodeon deploy\n";
  dc = dc + "version: '3.8'\n\n";
  dc = dc + "services:\n";
  dc = dc + "  app:\n";
  dc = dc + "    build: .\n";
  dc = dc + "    container_name: " + appName + "\n";
  dc = dc + "    ports:\n";
  dc = dc + "      - '" + port + ":" + port + "'\n";
  dc = dc + "    environment:\n";
  dc = dc + "      - NODE_ENV=production\n";
  dc = dc + "      - PORT=" + port + "\n";
  if (config.db) {
    dc = dc + "    depends_on:\n";
    dc = dc + "      - db\n";
    dc = dc + "    environment:\n";
    dc = dc + "      - DATABASE_URL=postgresql://nodeon:nodeon@db:5432/" + appName + "\n";
    dc = dc + "\n";
    dc = dc + "  db:\n";
    dc = dc + "    image: postgres:16-alpine\n";
    dc = dc + "    environment:\n";
    dc = dc + "      POSTGRES_USER: nodeon\n";
    dc = dc + "      POSTGRES_PASSWORD: nodeon\n";
    dc = dc + "      POSTGRES_DB: " + appName + "\n";
    dc = dc + "    volumes:\n";
    dc = dc + "      - pgdata:/var/lib/postgresql/data\n";
    dc = dc + "    ports:\n";
    dc = dc + "      - '5432:5432'\n";
    dc = dc + "\nvolumes:\n";
    dc = dc + "  pgdata:\n";
  }
  return dc;
}
function generateDockerignore() {
  return "node_modules\n.git\n.env\n*.log\nsrc\nbootstrap\ntests\n.windsurf\n";
}